    private left(i: number): number { return 2 * i + 1; }
    private right(i: number): number { return 2 * i + 2; }

    private swap(i: number, j: number): void {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    private bubbleUp(i: number): void {
        while (i > 0 && this.heap[this.parent(i)] > this.heap[i]) {
            this.swap(this.parent(i), i);
            i = this.parent(i);
        }
    }

    private sinkDown(i: number): void {
        let smallest = i;
        const l = this.left(i);
        const r = this.right(i);
        if (l < this.heap.length && this.heap[l] < this.heap[smallest]) smallest = l;
        if (r < this.heap.length && this.heap[r] < this.heap[smallest]) smallest = r;
        if (smallest !== i) {
            this.swap(i, smallest);
            this.sinkDown(smallest);
        }
